import React, { useState } from 'react';

export default function Controls({ onInsert, onExtract, onClear }) {
  const [key, setKey] = useState('');
  const [label, setLabel] = useState('');
  return (
    <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
      <input type="number" value={key} onChange={e => setKey(e.target.value)} placeholder="key (number)" />
      <input value={label} onChange={e => setLabel(e.target.value)} placeholder="label (optional)" />
      <button onClick={() => { if (key !== '') { onInsert(Number(key), label); setKey(''); setLabel(''); } }}>Insert</button>
      <button onClick={onExtract}>Extract Min</button>
      <button onClick={onClear}>Clear</button>
    </div>
  );
}
